import { EMPTY_DATE, RANGE_DELIMETER, RANGE_DELIMETER_SYMBOL } from '../Calendar/constants';
import { formatDateToISOWithTimeZone, maskDate, maskDateTime, parseTimeFromInput, RU_FORMAT_PATTERN_F } from '../utils';

export type RangeISO = [string, string];

// Верификация компонентов: используем только MaskField/TextField/CalendarRange через родительские компоненты
// Верификация токенов: визуальные значения не хардкодятся (логика парсинга/маски без стилей)

/**
 * Унифицированная обработка ввода одной строки для диапазона (DatePickerRange)
 * Возвращает замаскированную строку и ISO-значения для двух дат
 */
export function onRangeInputChange(
	updatedInputValue: string,
	prevInputValue: string | undefined,
	originalValue: RangeISO,
	enableImaskConfig: boolean | undefined,
	enableTimePicker: boolean | undefined,
): { maskedDate: string; newDateValue: RangeISO } {
	const isDeletion = !!prevInputValue && updatedInputValue.length < prevInputValue.length;
	if (!enableImaskConfig && isDeletion && updatedInputValue.endsWith(RANGE_DELIMETER_SYMBOL)) {
		return { maskedDate: updatedInputValue.slice(0, -2), newDateValue: originalValue };
	}

	const values = updatedInputValue.split(RANGE_DELIMETER_SYMBOL);
	const startDateStr = values[0]?.trim() ?? '';
	const endDateStr = values[1]?.trim() ?? EMPTY_DATE;

	const {
		date: startDate,
		hours: startHours,
		minutes: startMinutes,
	} = parseTimeFromInput(startDateStr, !!enableTimePicker);
	const { date: endDate, hours: endHours, minutes: endMinutes } = parseTimeFromInput(endDateStr, !!enableTimePicker);

	const startDateNew = startHours && startMinutes ? `${startDate} ${startHours}:${startMinutes}` : startDate;
	const isFilledStartDate = RU_FORMAT_PATTERN_F(!!enableTimePicker).test(startDateNew);

	if (isFilledStartDate) {
		const maskedEndDate = enableTimePicker
			? maskDateTime(endHours && endMinutes ? `${endDate} ${endHours}:${endMinutes}` : endDate)
			: maskDate(endDate);

		const maskedDate = startDateStr + RANGE_DELIMETER + maskedEndDate;
		const newDateValue: RangeISO = [
			formatDateToISOWithTimeZone(startDateStr, startHours, startMinutes, '00', !!enableTimePicker),
			formatDateToISOWithTimeZone(maskedEndDate, endHours, endMinutes, '00', !!enableTimePicker),
		];
		return { maskedDate, newDateValue };
	}

	const maskedStartDate = enableTimePicker ? maskDateTime(startDateStr) : maskDate(startDateStr);
	const needDeleteLastSymbol = maskedStartDate?.endsWith(RANGE_DELIMETER);

	const maskedDate = needDeleteLastSymbol ? maskedStartDate.slice(0, -1) : maskedStartDate;
	const newDateValue: RangeISO = [
		formatDateToISOWithTimeZone(maskedStartDate, startHours, startMinutes, '00', !!enableTimePicker),
		EMPTY_DATE,
	];
	return { maskedDate, newDateValue };
}

/**
 * Проверка необходимости очистки значений при закрытии для DatePickerRange
 */
export function shouldClearOnCloseRangeInput(
	currentText: string,
	prevInputValue: string | undefined,
	originalValue: RangeISO,
	enableImaskConfig: boolean | undefined,
	enableTimePicker: boolean | undefined,
	excludeDate?: (d: Date) => boolean,
	clearOnExcludedDateClose?: boolean,
): boolean {
	const { newDateValue } = onRangeInputChange(
		currentText,
		prevInputValue,
		originalValue,
		!!enableImaskConfig,
		!!enableTimePicker,
	);
	const [startStr, endStr] = newDateValue;
	const startDate = startStr ? new Date(startStr) : null;
	const endDate = endStr ? new Date(endStr) : null;

	if (startDate && endDate && enableImaskConfig) {
		if (clearOnExcludedDateClose && (excludeDate?.(startDate) || excludeDate?.(endDate))) {
			return true;
		}
	}
	return false;
}

/**
 * Проверка необходимости очистки значений при закрытии для DatePickerRangeSplit
 */
export function shouldClearOnCloseSplitInputs(
	startVal: string,
	endVal: string,
	currentInputValue: RangeISO,
	enableImaskConfig: boolean | undefined,
	enableTimePicker: boolean | undefined,
	excludeDate?: (d: Date) => boolean,
	clearOnExcludedDateClose?: boolean,
): boolean {
	const startISO = formatDateToISOWithTimeZone(startVal, '00', '00', '00', !!enableTimePicker);
	const endISO = formatDateToISOWithTimeZone(endVal, '00', '00', '00', !!enableTimePicker);
	const startDate = startISO ? new Date(startISO) : null;
	const endDate = endISO ? new Date(endISO) : null;

	const startInvalid = !startVal || !startDate || Number.isNaN(startDate.getTime());
	const endInvalid = !endVal || !endDate || Number.isNaN(endDate.getTime());
	const startExcluded = !!clearOnExcludedDateClose && !!excludeDate && !!startDate && excludeDate(startDate);
	const endExcluded = !!clearOnExcludedDateClose && !!excludeDate && !!endDate && excludeDate(endDate);

	const bothInputsNonEmpty = startVal !== '' && endVal !== '';
	const someDateInvalidOrExcluded = startInvalid || endInvalid || startExcluded || endExcluded;

	if (enableImaskConfig && bothInputsNonEmpty && someDateInvalidOrExcluded) {
		return true;
	}
	return false;
}

/**
 * Маска для RU-формата одной даты
 */
export function maskRuDate(dateStr: string, enableTimePicker: boolean | undefined): string {
	return enableTimePicker ? maskDateTime(dateStr) : maskDate(dateStr);
}

/**
 * Форматирование двух замаскированных дат в ISO для onChange
 */
export function toISOFromMaskedRange(
	startMasked: string,
	endMasked: string,
	enableTimePicker: boolean | undefined,
): RangeISO {
	return [
		formatDateToISOWithTimeZone(startMasked, '00', '00', '00', !!enableTimePicker),
		formatDateToISOWithTimeZone(endMasked, '00', '00', '00', !!enableTimePicker),
	];
}

/**
 * Валидация заполненности RU-формата для одной даты (через RU_FORMAT_PATTERN_F)
 */
export function isRuFilled(dateStr: string, enableTimePicker: boolean | undefined): boolean {
	return RU_FORMAT_PATTERN_F(!!enableTimePicker).test(dateStr);
}

